/** Global indices data for all 30 tracked countries.
 *  Each index uses official published data from the named source.
 *  null = country not included in that dataset. */

export interface IndexDefinition {
  id: string;
  name: string;
  fullName: string;
  source: string;
  year: number;
  scale: string;
  description: string;
  /** How to interpret this number — what does high/low actually mean? */
  interpretation: string;
  /** Important caveats or limitations of this index */
  caveats: string;
  higherIsBetter: boolean;
  icon: string;
  color: string;
  format: (v: number) => string;
}

export interface IndexStats {
  avg: number;
  min: number;
  max: number;
  minCountry: string;
  maxCountry: string;
  count: number;
}

