/** Get rank (1-based) of a country among the 30 tracked, for a given index.
 *  Returns null if country has no data for that index. */
export function getIndexRank(
  countryCode: string,
  indexId: string,
): number | null {
  const def = INDEX_DEFS.find((d) => d.id === indexId);
  if (!def) return null;
  const val = COUNTRY_INDICES[countryCode]?.[indexId];
  if (val == null) return null;

  const allValues = Object.entries(COUNTRY_INDICES)
    .map(([code, data]) => ({ code, value: data[indexId] }))
    .filter((e) => e.value != null) as { code: string; value: number }[];

  allValues.sort((a, b) =>
    def.higherIsBetter ? b.value - a.value : a.value - b.value,
  );

  return allValues.findIndex((e) => e.code === countryCode) + 1;
}

/** Compute avg / min / max across the 30 tracked countries for a given index. */
export function getIndexStats(indexId: string): IndexStats | null {
  const values: { code: string; value: number }[] = [];
  for (const [code, data] of Object.entries(COUNTRY_INDICES)) {
    const v = data[indexId];
    if (v != null) values.push({ code, value: v });
  }
  if (values.length === 0) return null;

  const def = INDEX_DEFS.find((d) => d.id === indexId);
  const sorted = [...values].sort((a, b) => a.value - b.value);
  const min = sorted[0];
  const max = sorted[sorted.length - 1];
  const avg = values.reduce((s, v) => s + v.value, 0) / values.length;

  // For display: "best" and "worst" depend on higherIsBetter
  const bestEntry = def?.higherIsBetter ? max : min;
  const worstEntry = def?.higherIsBetter ? min : max;

  return {
    avg,
    min: worstEntry.value,
    max: bestEntry.value,
    minCountry: worstEntry.code,
    maxCountry: bestEntry.code,
    count: values.length,
  };
}

// Country code → name mapping for stats display
const CODE_TO_NAME: Record<string, string> = {
  AR: "Argentina", AU: "Australia", BR: "Brazil", CA: "Canada", CL: "Chile",
  CN: "China", DK: "Denmark", FR: "France", DE: "Germany", GH: "Ghana",
  GR: "Greece", HU: "Hungary", IN: "India", IL: "Israel", IT: "Italy",
  JP: "Japan", KE: "Kenya", MX: "Mexico", NL: "Netherlands", NG: "Nigeria",
  PE: "Peru", PH: "Philippines", RU: "Russia", SG: "Singapore", ZA: "South Africa",
  KR: "South Korea", SE: "Sweden", TR: "Turkey", GB: "United Kingdom", US: "United States",
};

export function countryName(code: string): string {
  return CODE_TO_NAME[code] ?? code;
}
